revision.text:
{{#if:{{{3|}}}|{{#ifexpr:({{#time:U|{{{3}}}}} - {{#time:U|now}}) > 0|{{highlight/core|{{{1|}}}|{{#ifeq:{{{2|}}}||yellow|{{{2}}}}}}}|{{{1|}}}}}|{{highlight/core|{{{1|}}}|{{{2|yellow}}}}}}}<noinclude>{{documentation}}<templatedata>
{
	"params": {
		"1": {
			"aliases": [
				"text"
			],
			"label": "Text to be highlighted",
			"example": "Some text goes here",
			"type": "content",
			"required": true
		},
		"2": {
			"aliases": [
				"color"
			],
			"label": "Highlight color",
			"description": "CSS color to be used for highlight, like lightblue or #FF0066",
			"example": "lightblue",
			"type": "unknown",
			"default": "yellow"
		},
		"3": {
			"aliases": [
				"expiration"
			],
			"label": "Expiration date of highlight",
			"description": "After this date, the text will remain but the highlight color will not display.",
			"example": "2029-09-01",
			"type": "date"
		}
	},
	"description": "Highlights the given text.",
	"paramOrder": [
		"1",
		"2",
		"3"
	],
	"format": "inline"
}
</templatedata></noinclude>

